          longitude: 30.3146,
          title: "Исаакиевский собор",
          description: "Крупнейший православный храм Санкт-Петербурга",
          imageUrl: "https://upload.wikimedia.org/wikipedia/commons/thumb/7/78/St._Isaac%27s_Cathedral%2C_Saint_Petersburg.jpg/800px-St._Isaac%27s_Cathedral%2C_Saint_Petersburg.jpg",
          type: "religious",
          color: "#663399",
          address: "Санкт-Петербург, Исаакиевская площадь, 4",
          rating: 4.8,
          category: "Собор"
        }
      ];

      setMarkers(demoData);
      setCenter([demoData[0].latitude, demoData[0].longitude]);

    } catch (error) {
      console.error('Ошибка загрузки маркеров:', error);
      setMarkers(getDefaultMarkers());
    } finally {
      setLoading(false);
    }
  };

  // Создание SVG иконки
  const createMarkerIcon = (color = '#FF0000', type = 'default') => {
    const svg = `<svg width="48" height="48" viewBox="0 0 48 48" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <filter id="shadow" x="-20%" y="-20%" width="140%" height="140%">
          <feDropShadow dx="2" dy="2" stdDeviation="2" flood-opacity="0.3"/>
        </filter>
      </defs>
      <g filter="url(#shadow)">
        <circle cx="24" cy="24" r="18" fill="${color}" opacity="0.95"/>
        <circle cx="24" cy="24" r="10" fill="white"/>
        ${type === 'historic' ? '<path d="M24 15L27 22H32L26 26L28 33L24 29L20 33L22 26L16 22H21Z" fill="#FFD700"/>' : ''}
      </g>
    </svg>`;

    return `data:image/svg+xml;base64,${btoa(svg)}`;
  };

  // Функция для генерации HTML балуна с изображением
  const generateBalloonContent = (marker) => {
    return `
      <div style="
        max-width: 400px; 
        font-family: Arial, sans-serif;
        background: white;
        border-radius: 12px;
        overflow: hidden;
        box-shadow: 0 5px 20px rgba(0,0,0,0.15);
      ">
        <!-- Изображение -->
        <div style="position: relative; height: 200px; overflow: hidden;">
          <img 
            src="${marker.imageUrl}" 
            alt="${marker.title}"
            style="
              width: 100%;
              height: 100%;
              object-fit: cover;
              transition: transform 0.3s;
            "
            onmouseover="this.style.transform='scale(1.05)'"
            onmouseout="this.style.transform='scale(1)'"
          />
          <div style="
            position: absolute;
            top: 10px;
            right: 10px;
            background: ${marker.color};
            color: white;
            padding: 4px 10px;
            border-radius: 20px;
            font-size: 12px;
            font-weight: bold;
          ">
            ${marker.category || 'Место'}
          </div>
        </div>

        <!-- Информация -->
        <div style="padding: 20px;">
          <h3 style="
            margin: 0 0 10px 0;
            color: #333;
            font-size: 20px;
            font-weight: 600;
          ">
            ${marker.title}
          </h3>

          <p style="
            margin: 0 0 15px 0;
            color: #666;
            font-size: 14px;
            line-height: 1.5;
          ">
            ${marker.description}
          </p>

          <div style="
            display: flex;
            align-items: center;
            margin-bottom: 15px;
            gap: 10px;
          ">
            <div style="
              display: flex;
              align-items: center;
              color: #FF9900;
              font-weight: bold;
            ">
              ★ ${marker.rating || '4.5'}
            </div>
            <div style="
              padding: 4px 8px;
              background: #f0f0f0;
              border-radius: 4px;
              font-size: 12px;
              color: #666;
            ">
              ${marker.type}
            </div>
          </div>

          <!-- Координаты и адрес -->
          <div style="
            background: #f8f9fa;
            padding: 15px;
            border-radius: 8px;
            margin-bottom: 15px;
          ">
            <div style="
              display: grid;
              grid-template-columns: 1fr 1fr;
              gap: 10px;
              margin-bottom: 10px;
            ">
              <div>
                <div style="
                  font-size: 11px;
                  color: #888;
                  margin-bottom: 4px;
                ">
                  Широта
                </div>
                <div style="
                  font-family: 'Courier New', monospace;
                  font-size: 13px;
                  color: #333;
                  font-weight: bold;
                ">
                  ${marker.latitude.toFixed(6)}
                </div>
              </div>
              <div>
                <div style="
                  font-size: 11px;
                  color: #888;
                  margin-bottom: 4px;
                ">
                  Долгота
                </div>
                <div style="
                  font-family: 'Courier New', monospace;
                  font-size: 13px;
                  color: #333;
                  font-weight: bold;
                ">
                  ${marker.longitude.toFixed(6)}
                </div>
              </div>
            </div>

            <div>
              <div style="
                font-size: 11px;
                color: #888;
                margin-bottom: 4px;
              ">
                Адрес
              </div>
              <div style="
                font-size: 13px;
                color: #333;
              ">
                ${marker.address}
              </div>
            </div>
          </div>

          <!-- Дополнительные действия -->
          <div style="
            display: flex;
            gap: 10px;
            justify-content: space-between;
          ">
            <button 
              onclick="window.openMarkerDetails(${marker.id})"
              style="
                flex: 1;
                padding: 10px;
                background: ${marker.color};
                color: white;
                border: none;
                border-radius: 6px;
                font-weight: bold;
                cursor: pointer;
                transition: opacity 0.3s;
              "
              onmouseover="this.style.opacity='0.9'"
              onmouseout="this.style.opacity='1'"
            >
              Подробнее
            </button>
            <button 
              onclick="window.copyCoordinates(${marker.latitude}, ${marker.longitude})"
              style="
                padding: 10px 15px;
                background: #6c757d;
                color: white;
                border: none;
                border-radius: 6px;
                cursor: pointer;
                transition: background 0.3s;
              "
              onmouseover="this.style.background='#5a6268'"
              onmouseout="this.style.background='#6c757d'"
            >
              📋 Координаты
            </button>
          </div>
        </div>
      </div>
    `;
  };

  // Глобальные функции для кнопок в балуне
  useEffect(() => {
    window.openMarkerDetails = (id) => {
      alert(`Открыть детали маркера с ID: ${id}`);
      // В реальном приложении: переход на страницу маркера или открытие модального окна
    };

    window.copyCoordinates = (lat, lon) => {
      navigator.clipboard.writeText(`${lat}, ${lon}`)
        .then(() => alert('Координаты скопированы!'))
        .catch(err => console.error('Ошибка копирования:', err));
    };

    return () => {
      delete window.openMarkerDetails;
      delete window.copyCoordinates;
    };
  }, []);

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '600px',
        flexDirection: 'column',
        gap: '20px'
      }}>
        <div style={{
          width: '50px',
          height: '50px',
          border: '5px solid #f3f3f3',
          borderTop: '5px solid #3498db',
          borderRadius: '50%',
          animation: 'spin 1s linear infinite'
        }}></div>
        <style>{`
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
        `}</style>
        <div>Загрузка карты и маркеров...</div>
      </div>
    );
  }

  return (
    <div style={{ 
      width: '100%', 
      maxWidth: '1200px', 
      margin: '0 auto',
      padding: '20px'
    }}>
      <h1 style={{ marginBottom: '20px', color: '#333' }}>
        Карта достопримечательностей
        <span style={{
          fontSize: '14px',
          color: '#666',
          marginLeft: '10px',
          backgroundColor: '#f0f0f0',
          padding: '4px 10px',
          borderRadius: '20px'
        }}>
          {markers.length} мест
        </span>
      </h1>

      <div style={{ 
        width: '100%', 
        height: '600px',
        borderRadius: '12px',
        overflow: 'hidden',
        boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
        marginBottom: '20px'
      }}>
        <YMaps>
          <Map 
            state={{ center, zoom: 10 }} 
            width="100%" 
            height="100%"
            modules={['geoObject.addon.balloon', 'geoObject.addon.hint']}
          >
            {markers.map((marker) => (
              <Placemark
                key={marker.id}
                geometry={[marker.latitude, marker.longitude]}
                options={{
                  iconLayout: 'default#image',
                  iconImageHref: createMarkerIcon(marker.color, marker.type),
                  iconImageSize: [48, 48],
                  iconImageOffset: [-24, -48],
                  hideIconOnBalloonOpen: false,
                  openBalloonOnClick: true,
                }}
                properties={{
                  hintContent: `<div style="padding: 5px 10px; font-weight: bold;">${marker.title}</div>`,
                  balloonContent: generateBalloonContent(marker),
                  balloonContentHeader: `<div style="padding: 10px; background: ${marker.color}; color: white; font-weight: bold; border-radius: 8px 8px 0 0;">${marker.title}</div>`,
                }}
                modules={['geoObject.addon.balloon']}
                onClick={() => {
                  setSelectedMarker(marker);
                  console.log('Выбран маркер:', marker.title);
                }}
              />
            ))}
          </Map>
        </YMaps>
      </div>

      {/* Информационная панель */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
        gap: '20px',
        marginTop: '30px'
      }}>
        {markers.map(marker => (
          <div 
            key={marker.id}
            style={{
              background: 'white',
              borderRadius: '10px',
              overflow: 'hidden',
              boxShadow: '0 2px 10px rgba(0,0,0,0.08)',
              cursor: 'pointer',
              transition: 'transform 0.2s, box-shadow 0.2s',
              border: selectedMarker?.id === marker.id ? `2px solid ${marker.color}` : '2px solid transparent'
            }}
            onClick={() => {
              setSelectedMarker(marker);
              setCenter([marker.latitude, marker.longitude]);
            }}
            onMouseOver={(e) => e.currentTarget.style.transform = 'translateY(-5px)'}
            onMouseOut={(e) => e.currentTarget.style.transform = 'translateY(0)'}
          >
            <div style={{
              height: '120px',
              overflow: 'hidden'
            }}>
              <img 
                src={marker.imageUrl} 
                alt={marker.title}
                style={{
                  width: '100%',
                  height: '100%',
                  objectFit: 'cover'
                }}
              />
            </div>
            <div style={{ padding: '15px' }}>
              <div style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'flex-start',
                marginBottom: '8px'
              }}>
                <h3 style={{ margin: 0, fontSize: '16px' }}>{marker.title}</h3>
                <div style={{
                  fontSize: '12px',
                  background: marker.color,
                  color: 'white',
                  padding: '3px 8px',
                  borderRadius: '12px'
                }}>
                  {marker.category}
                </div>
              </div>
              <p style={{
                fontSize: '13px',
                color: '#666',
                margin: '0 0 10px 0',
                lineHeight: '1.4'
              }}>
                {marker.description.length > 80 ? `${marker.description.substring(0, 80)}...` : marker.description}
              </p>
              <div style={{
                fontSize: '11px',
                color: '#888',
                fontFamily: 'monospace'
              }}>
                {marker.latitude.toFixed(4)}, {marker.longitude.toFixed(4)}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

